    /// <summary>
    /// The Win32_SystemAccount class represents a system account. <br/>
    /// The system account is used by the operating system and by services that run under Windows NT. <br/>
    /// There are many services and processes within NT that need the capability to logon internally (for example during a Windows NT installation). <br/>
    /// The system account was designed for that purpose; it is an internal account, does not show up in User Manager, cannot be added to any groups, and cannot have user rights assigned to it. <br/>
    /// On the other hand, the system account does show up on an NTFS volume in File Manager in the Permissions portion of the Security menu. <br/>
    /// By default, the system account is granted full control to all files on an NTFS volume. <br/>
    /// Here the system account has the same functional privileges as the administrator account. <br/>
    ///  <br/>
    /// provider: CIMWin32 <br/>
    ///  <br/>
    /// uuid: {8502C4CA-5FBB-11D2-AAC1-006008C78BC7} <br/>
    ///  <br/>
    /// </summary>
    public class Win32_SystemAccount
    {
        /// <summary>
        ///  <br/>
        /// cimtype: string <br/>
        ///  <br/>
        /// </summary>
        public String Caption { get; set; }
        /// <summary>
        ///  <br/>
        /// cimtype: string <br/>
        ///  <br/>
        /// </summary>
        public String Description { get; set; }
        /// <summary>
        /// The Domain property indicates the name of the Windows domain to which the system account belongs. <br/>
        /// Example: NA-SALES <br/>
        ///  <br/>
        /// cimtype: string <br/>
        ///  <br/>
        /// override: Domain <br/>
        ///  <br/>
        /// </summary>
